<?php declare(strict_types=1); use App\Support\VietnameseFormatter; ?>
<section class="page-header"><div><span class="eyebrow">HẠNG THÀNH VIÊN</span><h1>Cấu hình hạng và quyền lợi</h1><p>Ngưỡng, point rate và quyền lợi được tải từ database khi xử lý nghiệp vụ.</p></div><div class="action-group"><a class="button button-primary" href="/admin/hang-thanh-vien/them">Thêm hạng</a><a class="button button-outline" href="/admin/quyen-loi/them">Thêm quyền lợi</a></div></section>
<?php if (isset($flashSuccess) && is_string($flashSuccess)): ?><div class="notification notification-success" role="status"><strong>Thành công</strong><span><?= $e($flashSuccess) ?></span></div><?php endif; ?>
<section class="content-section"><h2>Quy tắc hạng</h2><?php if ($tiers === []): ?><div class="empty-state"><h3>Chưa có hạng</h3></div><?php else: ?><div class="table-shell"><table><thead><tr><th>Hạng</th><th>Điều kiện</th><th>Đặt trước / điểm</th><th>Trạng thái</th><th>Thao tác</th></tr></thead><tbody><?php foreach ($tiers as $tier): ?><tr><td><strong><?= $e($tier['name']) ?></strong><br><?= $e($tier['code']) ?> · #<?= $e($tier['rank_order']) ?></td><td><?= $e(VietnameseFormatter::vnd((string) $tier['min_monthly_spend'])) ?> và <?= $e($tier['min_monthly_visits']) ?> lượt</td><td><?= $e($tier['booking_window_days']) ?> ngày · ×<?= $e($tier['point_rate']) ?></td><td><span class="status-badge <?= $tier['is_active'] ? 'status-completed' : 'status-neutral' ?>"><?= $tier['is_active'] ? 'Hoạt động' : 'Đã ngừng' ?></span></td><td><div class="action-group"><a class="button button-outline button-compact" href="/admin/hang-thanh-vien/<?= $e($tier['id']) ?>/sua">Sửa</a><form method="post" action="/admin/hang-thanh-vien/<?= $e($tier['id']) ?>/<?= $tier['is_active'] ? 'ngung-hoat-dong' : 'kich-hoat' ?>"><input type="hidden" name="_csrf_token" value="<?= $e($csrfToken) ?>"><button class="button button-ghost button-compact"><?= $tier['is_active'] ? 'Ngừng' : 'Kích hoạt' ?></button></form></div></td></tr><?php endforeach; ?></tbody></table></div><?php endif; ?></section>
<section class="content-section"><h2>Quyền lợi tự động</h2><?php if ($perks === []): ?><div class="empty-state"><h3>Chưa có quyền lợi</h3><p>Booking vẫn hoạt động và discount perk bằng 0.</p></div><?php else: ?><div class="table-shell"><table><thead><tr><th>Hạng</th><th>Loại / giá trị</th><th>Dịch vụ</th><th>Trạng thái</th><th>Thao tác</th></tr></thead><tbody><?php foreach ($perks as $perk): ?><tr><td><?= $e($perk['tier_name']) ?></td><td><?= $e($perk['perk_type']) ?> · <?= $e($perk['value']) ?></td><td><?= $perk['service_name'] === null ? 'Không giới hạn' : $e($perk['service_name']) ?></td><td><?= $perk['is_active'] ? 'Hoạt động' : 'Đã ngừng' ?></td><td><div class="action-group"><a class="button button-outline button-compact" href="/admin/quyen-loi/<?= $e($perk['id']) ?>/sua">Sửa</a><form method="post" action="/admin/quyen-loi/<?= $e($perk['id']) ?>/<?= $perk['is_active'] ? 'ngung-hoat-dong' : 'kich-hoat' ?>"><input type="hidden" name="_csrf_token" value="<?= $e($csrfToken) ?>"><button class="button button-ghost button-compact"><?= $perk['is_active'] ? 'Ngừng' : 'Kích hoạt' ?></button></form></div></td></tr><?php endforeach; ?></tbody></table></div><?php endif; ?></section>
